from sklearn.neighbors import NearestNeighbors

def compute_target_gradients(X, y, k=None):
    """
    Unified Sobolev target-gradient estimator.

    Dispatches to the appropriate method based on input dimensionality:
      - 1-D: finite differences on the sorted (x, y) pairs — exact and fast.
      - N-D (n_features >= 2): KNN local-linear regression, which estimates
        the full Jacobian vector ∂y/∂x_j for every point simultaneously.

    Returns
    -------
    grads : ndarray, shape (N, D)
        Estimated partial derivatives dy/dx_j at each training point.
        For 1-D output grads[:, 0] is the ordinary derivative.
    """
    if k is None:
        k = SOBOLEV_KNN_K
    N, D = X.shape
    if D == 1:
        # 1-D: sort by x, use np.gradient (central differences), then unsort.
        order   = np.argsort(X[:, 0])
        x_sorted = X[order, 0]
        y_sorted = y[order]
        dy_dx    = np.gradient(y_sorted, x_sorted)
        grads    = np.empty((N, 1), dtype=np.float64)
        grads[order, 0] = dy_dx
        return np.clip(np.nan_to_num(grads, nan=0.0, posinf=1e5, neginf=-1e5), -1e5, 1e5)
    else:
        return compute_multivariate_target_gradients(X, y, k=k)


def compute_multivariate_target_gradients(X, y, k=15):
    """
    Estimates dy/dx for unstructured multivariate data using local linear regression.
    Works natively for 1D, 2D, and ND datasets.

    Fully vectorised using batched normal equations with Tikhonov regularisation:
        g_i = (X_local^T X_local + λI)^{-1} X_local^T y_local
    for each point i, solved in a single batched np.linalg.solve call — O(N·D³)
    instead of O(N) Python-level lstsq calls.  For D≤~15 and N≤50 000 this is
    typically 10-50× faster than the loop version.
    """
    N, D = X.shape
    k = min(k, N)

    nbrs = NearestNeighbors(n_neighbors=k).fit(X)
    _, indices = nbrs.kneighbors(X)

    # Build centred neighbourhoods: (N, K, D) and (N, K)
    X_local = X[indices] - X[:, np.newaxis, :]   # (N, K, D)
    y_local = y[indices] - y[:, np.newaxis]       # (N, K)

    # Normal equations: (N, D, D) @ g = (N, D)
    XTX = np.einsum('nkd,nke->nde', X_local, X_local)   # (N, D, D)
    XTy = np.einsum('nkd,nk->nd',  X_local, y_local)    # (N, D)

    # Tikhonov regularisation: λ = 1e-6 × mean diagonal (scale-adaptive ridge)
    diag_mean = XTX.reshape(N, -1)[:, ::D + 1].mean(axis=1).clip(min=1e-8)
    lam = 1e-6 * diag_mean                               # (N,)
    eye = np.eye(D, dtype=X.dtype)[np.newaxis]           # (1, D, D)
    XTX += lam[:, np.newaxis, np.newaxis] * eye

    try:
        target_grads = np.linalg.solve(XTX, XTy[..., np.newaxis])[..., 0]   # (N, D)
    except np.linalg.LinAlgError:
        # Singular batches: fall back to per-point lstsq (rare, small N)
        target_grads = np.zeros((N, D), dtype=np.float64)
        for i in range(N):
            g, _, _, _ = np.linalg.lstsq(X_local[i], y_local[i], rcond=None)
            target_grads[i] = g

    return np.clip(np.nan_to_num(target_grads, nan=0.0, posinf=1e5, neginf=-1e5), -1e5, 1e5)
def evaluate_tree_gradients(tree, X, affine_a, eps=1e-5):
    """
    Computes the gradient of the CGP tree w.r.t each input feature using central differences.
    """
    N, D = X.shape
    grads = np.zeros((N, D))
    
    for j in range(D):
        X_plus = X.copy()
        X_plus[:, j] += eps
        y_plus = tree.evaluate(X_plus)
        
        X_minus = X.copy()
        X_minus[:, j] -= eps
        y_minus = tree.evaluate(X_minus)
        
        # Don't forget the affine scaling applies to the derivative too!
        # d/dx (a * f(x) + b) = a * f'(x)
        raw_grad = (y_plus - y_minus) / (2 * eps)
        grads[:, j] = affine_a * raw_grad

    # Sanitize to prevent explosions from polluting the loss
    return np.clip(np.nan_to_num(grads, nan=0.0, posinf=1e5, neginf=-1e5), -1e5, 1e5)


def _multiclass_sample_weights(yg, mode=None):
    """
    Per-sample weights for a one-hot multi-class label matrix `yg` (N, K).

    Returns an (N,) array whose mean is 1.0 (so the over-all loss scale stays
    comparable to the unweighted case), with each sample weighted inversely to
    its true class's empirical frequency.

    Returns None when class-weighting is disabled (mode='none' or
    CLASS_WEIGHT_ENABLED is False).
    """
    if yg is not None and len(yg.shape) == 1:
        yg = np.eye(2)[yg.astype(int)]
    if mode is None:
        mode = CLASS_WEIGHT_MODE
    if (not CLASS_WEIGHT_ENABLED) or mode == 'none' or yg is None:
        return None
    counts = yg.sum(axis=0)  # (K,)
    K = yg.shape[1]
    # Guard against zero-count classes in this batch.
    # We replace zero counts with 1.0 to avoid division by zero. Since the class
    # is not present in the batch, it will not be accessed by `sw = cls_w[true_cls]`.
    if not np.all(counts > 0):
        counts = np.where(counts == 0, 1.0, counts)
    N = float(yg.shape[0])
    if mode == 'balanced':
        cls_w = N / (K * counts)
    elif mode == 'sqrt_balanced':
        cls_w = np.sqrt(N / (K * counts))
    else:
        return None
    true_cls = np.argmax(yg, axis=1)
    sw = cls_w[true_cls]
    # Re-normalise to mean 1.0 (defensive — the formulas above already do this
    # under exact label counts, but minibatches can drift)
    m = float(np.mean(sw))
    if m > 1e-12:
        sw = sw / m
    return sw


def _binary_sample_weights(y_eval, mode=None):
    """
    Per-sample weights for a binary target vector `y_eval` (treated as 0/1).
    Mean is normalised to 1.0.  Returns None when weighting is disabled or the
    batch is degenerate (all-one-class).
    """
    if mode is None:
        mode = CLASS_WEIGHT_MODE
    if (not CLASS_WEIGHT_ENABLED) or mode == 'none' or y_eval is None:
        return None
    y_bin = (np.asarray(y_eval) >= 0.5).astype(np.float64)
    n_pos = float(y_bin.sum())
    n_neg = float(len(y_bin) - n_pos)
    if n_pos < 1.0 or n_neg < 1.0:
        # Degenerate batch — no minority class present.  Skip weighting so we
        # don't divide by zero or amplify noise.
        return None
    N = float(len(y_bin))
    if mode == 'balanced':
        w_pos, w_neg = N / (2.0 * n_pos), N / (2.0 * n_neg)
    elif mode == 'sqrt_balanced':
        w_pos = np.sqrt(N / (2.0 * n_pos))
        w_neg = np.sqrt(N / (2.0 * n_neg))
    else:
        return None
    sw = y_bin * w_pos + (1.0 - y_bin) * w_neg
    m = float(np.mean(sw))
    if m > 1e-12:
        sw = sw / m
    return sw


# ==========================================
# DATA-SCALE HINT & TYPE-COERCION HELPERS
# ==========================================
# Dataset-scale hint set once during train_mode after preprocessing.  Used by
# the constant optimiser to size DE bounds, by mutation operators to generate
# new constants on the right order of magnitude, and by _random_const to seed
# initial populations near plausible scales.  Without this, a dataset whose
# answer involves constants like 700_000 or 30 is unreachable from the default
# magnitudes (gauss(0, 2) * 1000 ≈ 6000 maximum).
_DATA_SCALE_HINT = 10.0

def _set_data_scale_hint(X, Y):
    """Set the module-level _DATA_SCALE_HINT from training data."""
    global _DATA_SCALE_HINT
    try:
        parts = []
        if X is not None and getattr(X, 'size', 0) > 0:
            xa = np.abs(np.asarray(X, dtype=float))
            xa = xa[np.isfinite(xa)]
            if xa.size > 0:
                parts.append(float(np.max(xa)))
        if Y is not None and getattr(Y, 'size', 0) > 0:
            ya = np.abs(np.asarray(Y, dtype=float))
            ya = ya[np.isfinite(ya)]
            if ya.size > 0:
                parts.append(float(np.max(ya)))
        if parts:
            s = max(parts)
            if np.isfinite(s) and s > 0:
                _DATA_SCALE_HINT = max(10.0, s)
    except Exception:
        pass
    return _DATA_SCALE_HINT


# Tokens recognised as boolean values when a user picks a numeric type on an
# object/string column.  Case-insensitive.  Y/N and 1/0 are included so binary
# survey-style data ("Y", "N") and 0/1 strings ("0", "1") all collapse to
# clean 0.0/1.0 numerics without needing one-hot encoding.
_BOOLEAN_TRUE_TOKENS  = frozenset({'true',  't', 'yes', 'y'})
_BOOLEAN_FALSE_TOKENS = frozenset({'false', 'f', 'no',  'n'})

def _detect_boolean_like_column(col_data):
    """
    Inspect *col_data* (object/string column).  If every non-null value is one
    of True/False or Yes/No/Y/N (case-insensitive), return
    ``(True, true_tokens, false_tokens)`` describing which tokens map to 1
    and which to 0.  Otherwise return ``(False, None, None)``.
    """
    try:
        s = pd.Series(col_data)
        s = s[s.notna()]
        if len(s) == 0:
            return False, None, None
        tokens = set(str(v).strip().lower() for v in s.values)
        if not tokens:
            return False, None, None
        if tokens.issubset({'true', 'false'}):
            return True, {'true'}, {'false'}
        if tokens.issubset({'t', 'f'}):
            return True, {'t'}, {'f'}
        # Yes/No (allow Y and N mixed with Yes and No)
        if tokens.issubset({'yes', 'no', 'y', 'n'}):
            return True, {'yes', 'y'}, {'no', 'n'}
        return False, None, None
    except Exception:
        return False, None, None


def _convert_boolean_column_to_numeric(col_data, true_tokens, false_tokens):
    """
    Map each entry of *col_data* to 1.0 if it matches *true_tokens*, 0.0 if
    it matches *false_tokens*, NaN otherwise (preserves missing values so the
    downstream imputer can decide how to fill them).
    """
    out = np.full(len(col_data), np.nan, dtype=float)
    for i, v in enumerate(col_data):
        if v is None:
            continue
        # pd.isna handles both None and float NaN; guard against array-likes.
        try:
            if pd.isna(v):
                continue
        except (TypeError, ValueError):
            pass
        s = str(v).strip().lower()
        if s in true_tokens:
            out[i] = 1.0
        elif s in false_tokens:
            out[i] = 0.0
    return out


def _is_object_like_dtype(dtype):
    """
    True if *dtype* is non-numeric and holds strings/mixed values.  Handles
    both numpy ``object`` arrays (pandas <2.x default) and the modern pandas
    ``string`` / StringArray dtype.  ``dtype == object`` alone misses the
    latter on pandas ≥ 2.0.
    """
    try:
        if pd.api.types.is_numeric_dtype(dtype):
            return False
        if pd.api.types.is_bool_dtype(dtype):
            return False
        if pd.api.types.is_datetime64_any_dtype(dtype):
            return False
        # Catch object, string, category, and the generic 'O' kind.
        if pd.api.types.is_string_dtype(dtype):
            return True
        if hasattr(dtype, 'kind') and dtype.kind == 'O':
            return True
        return False
    except Exception:
        return False


def _column_is_mostly_numeric(col_data, threshold=0.8):
    """
    Return True if at least *threshold* of the non-null values in *col_data*
    can be parsed as numbers via pd.to_numeric.  Used to decide whether an
    object-dtype column the user marked as numeric is genuinely numeric
    (stored as strings like '1.5') vs. truly categorical strings.
    """
    try:
        s = pd.Series(col_data)
        n_non_null = int(s.notna().sum())
        if n_non_null == 0:
            return True
        parsed = pd.to_numeric(s, errors='coerce')
        return int(parsed.notna().sum()) / n_non_null >= threshold
    except Exception:
        return False


# --- CONFIGURATION ---
POPULATION_SIZE = 200
