# ---- Arithmetic Interval mode ----
# Runs Unsafe ops but periodically evaluates every individual against the
# FULL training input range.  Any individual whose expression yields NaN or
# Inf on any training row is immediately penalised / discarded.
# Unlike naive symbolic interval arithmetic this handles the actual data
# distribution (including all interaction patterns between variables).
INTERVAL_MODE       = False   # set interactively via select_ops_safety()
INTERVAL_CHECK_FREQ = 100     # how often (in generations) to run stability scan

# ---- Logit Saturation Penalty (Interval Mode) ----
# When INTERVAL_MODE is enabled for classification outputs, penalise individuals
# whose raw logit outputs are extremely saturated (|logit| >> threshold).
# Saturated logits map to probabilities ≈ 0 or ≈ 1 through sigmoid/softmax,
# causing:  (a) overconfident predictions that don't generalise,
#           (b) vanishing gradients for boosting pseudo-residuals,
#           (c) numerical issues in BCE/softmax CE computation.
# The penalty is: WEIGHT * mean(max(0, |logit| - THRESHOLD)²)
# This keeps logits in a numerically healthy range without restricting the
# sign or rough magnitude of the output.
# Also available for regression to discourage extreme prediction magnitudes.
LOGIT_SATURATION_THRESHOLD  = 12.0   # |logit| above this is penalised
LOGIT_SATURATION_WEIGHT     = 0.05   # penalty coefficient
LOGIT_SATURATION_REG_ENABLE = False  # also apply to regression (extreme pred penalty)

# ---- Class-Imbalance Handling ----
# With unbalanced multiclass / binary classification targets, the un-weighted
# softmax-CE / BCE loss is dominated by the majority class.  Evolution then
# converges to "predict the majority class" because rare-class samples only
# contribute a tiny fraction of the mean loss — exactly the failure mode the
# user reported on the orbital-temperature dataset (Habitable rows are ~7 %).
#
# When CLASS_WEIGHT_MODE is non-'none', each sample contributes to the loss
# weighted by 1/freq(true_class), normalised so the mean weight stays ≈1.
# This gives every class equal voice in the gradient-search signal, so rare
# classes get developed instead of being absorbed into the majority prior.
#
# Modes:
#   'none'           → no re-weighting (legacy behaviour)
#   'balanced'       → w_c = N / (K · count_c) (sklearn-style; strongest)
#   'sqrt_balanced'  → w_c = sqrt(N / (K · count_c)) (gentler; recommended
#                      default — strong enough to develop rare classes
#                      without making rare-class noise dominate)
#
# Applied to:
#   • Softmax-CE loss for multi-class one-hot groups (calculate_fitness)
#   • BCE loss for binary classification outputs (calculate_fitness)
#   • optimize_constants objective for both above
#   • epsilon-lexicase per-case errors (so rare-class cases survive case-by-case
#     filtering in proportion to their importance, not their raw count)
#   • Gradient-boosting Hessian weights (so the regression-on-residuals stage
#     upweights rare-class rows when fitting pseudo-residuals)
#
# Accuracy/argmax metrics remain unweighted so they stay comparable.
CLASS_WEIGHT_MODE     = 'sqrt_balanced'  # 'none' | 'balanced' | 'sqrt_balanced'
CLASS_WEIGHT_ENABLED  = True             # toggled interactively at startup

# ---- Bayesian CGP Settings ----
# Bayesian optimisation uses a Gaussian Process surrogate to model the
# fitness landscape over CGP genotype space, and Expected Improvement (EI)
# to pick which candidate mutations to actually evaluate.  This is much
# more sample-efficient than pure evolution but more expensive per iteration.
BAYESIAN_INITIAL_SAMPLES = 100    # random individuals evaluated before BO starts
BAYESIAN_BATCH_SIZE      = 30     # candidates evaluated per BO iteration
                                  # (20→30 to give the per-iter BO throughput
                                  # a closer match to a single evolutionary
                                  # island's per-generation eval count — BO
                                  # is single-process so it has to make each
                                  # iter count)
BAYESIAN_N_CANDIDATES    = 200    # mutation candidates generated per iteration
BAYESIAN_GP_REFIT_FREQ   = 5      # refit GP every N iterations
BAYESIAN_EXPLORATION     = 0.05   # exploration–exploitation trade-off (xi for EI)
                                  # Bumped 0.01 → 0.05 because at 0.01 EI was
                                  # essentially greedy on the GP's best-of-buffer
                                  # estimate; the surrogate is uncertain over
                                  # most of the encoding manifold for CGP, so
                                  # we need more xi for the acquisition to ever
                                  # pick candidates that aren't structurally
                                  # adjacent to the existing buffer best.
BAYESIAN_MAX_GP_POINTS   = 500    # cap on GP training set (oldest evicted first)
BAYESIAN_CONST_OPT_FREQ  = 10     # run light const-opt on HoF every N iterations
BAYESIAN_VARIANT         = "regular" # bayesian variant

# ── Interplay Escape Oracle ──────────────────────────────────────────
# The Bayesian surrogate is excellent at refining variants of a template
# that already scores well — and that's exactly its failure mode on
# multi-interplay targets like
#     (A·B)·log(B) − 10·A / (√(A·B) + (B−A) − (B/A) − (A/√B))
# where the answer requires composing ~6 distinct (op_cat, feat_pair)
# interplays.  Once EI locks onto one good basin the GP only ever sees
# variants of that basin, and the search converges to whichever single
# template fits best instead of building the compound expression.
#
# The Interplay Escape Oracle gives the Bayesian a way to act as the
# "intelligent evolution master" the underlying engines need:
#   1. It records the (op_category, feature_ancestor_set) atoms that
#      appear in every evaluated tree, and the full structural signature
#      of each candidate.
#   2. When recent buffer additions collapse onto a single dominant
#      signature (low entropy / one signature claiming >threshold of
#      the buffer) for several consecutive iterations, the oracle
#      flags "escape mode" for ESCAPE_DURATION iterations.
#   3. During escape mode, the outer BO loop:
#        - allocates ESCAPE_SEED_FRAC of its candidate budget to seeds
#          synthesised against MISSING atoms (interplays never seen),
#        - uses a Boltzmann (softmax-over-loss) Stage-2 selection at
#          temperature ESCAPE_TEMPER_T so screen-losers occasionally
#          get full evaluation — the "be less afraid to try worse
#          formulas" mechanism,
#        - asks the GP-Hedge portfolio to boost its exploration arms
#          (UCB / PE / TS / KG) so the surrogate's acquisition stops
#          ranking everything by the basin's local gradient.
# Set BAYESIAN_ESCAPE_ENABLED = False to disable the oracle entirely.
BAYESIAN_ESCAPE_ENABLED       = True   # master switch for the oracle
BAYESIAN_ESCAPE_PATIENCE      = 6      # consecutive low-entropy iters before escape fires
BAYESIAN_ESCAPE_ENTROPY_FRAC  = 0.55   # H / log(unique_signatures) below this counts as inbred
BAYESIAN_ESCAPE_DOMINANT_FRAC = 0.50   # one signature claiming >this of buffer also counts
BAYESIAN_ESCAPE_DURATION      = 4      # iters spent in escape mode per trigger
BAYESIAN_ESCAPE_SEED_FRAC     = 0.25   # candidate-budget share devoted to escape seeds
BAYESIAN_ESCAPE_TEMPER_T      = 1.5    # Stage-2 softmax temperature (× loss range)
BAYESIAN_ESCAPE_RECENT_WINDOW = 30     # iterations tracked in the recent-signature window

QUALITY_DIVERSITY_ENABLED = False # QD algorithms



