# ----- STRING REPR TABLE -----
def _binary_str(op, s1, s2):
    if op in ['+', '-', '*']:
        return f"({s1} {op} {s2})"
    elif op == '/':
        return f"({s1} / {s2})"
    elif op == 'floordiv':
        return f"floor({s1} / {s2})"
    elif op == 'pow':
        if SAFE_OPS_MODE:
            return f"(abs({s1})^{s2})"
        else:
            return f"({s1}^{s2})"
    elif op == 'gt':
        return f"({s1} > {s2})"
    elif op == 'lt':
        return f"({s1} < {s2})"
    elif op == 'gte':
        return f"({s1} >= {s2})"
    elif op == 'lte':
        return f"({s1} <= {s2})"
    elif op.startswith('adf_'):
        return f"{op}({s1}, {s2})"
    else:
        return f"{op}({s1}, {s2})"

def _ternary_str(op, s1, s2, s3):
    """String representation for ternary operators (if_else)."""
    if op == 'if_else':
        return f"IF({s1} THEN {s2} ELSE {s3})"
    return f"{op}({s1}, {s2}, {s3})"

def _unary_str(op, s1):
    if op == '10^x':
        return f"10^({s1})"
    if op == 'square':
        return f"({s1})²"
    if op == 'neg':
        return f"(-{s1})"
    if op == 'frac':
        return f"frac({s1})"
    if op == 'round':
        return f"round({s1})"
    return f"{op}({s1})"


